import React, {useMemo} from "react";
import type {IBadgeProps, IconName} from "@lmb-it/kitsconcerto-types";
import {ResponsiveElement, useSeparator} from "../../factory";
import {useComponentDefaults} from "../../hooks";
import {useSeverityColors} from "../../hooks/useSeverityColors";
import {IconMap} from "../../assets/Icons";

/* ─── Size config ─────────────────────────────────────────────── */
const SIZE_MAP = {
    sm:  {fontSize: 10, px: 6,  py: 2,  gap: 4, iconSize: 12, dotSize: 6},
    md:  {fontSize: 12, px: 10, py: 4,  gap: 6, iconSize: 14, dotSize: 8},
    lg:  {fontSize: 14, px: 12, py: 6,  gap: 6, iconSize: 16, dotSize: 10},
} as const;

/* ─── Icon resolver ──────────────────────────────────────────── */
function resolveIcon(icon: unknown, color: string, iconSize: number): React.ReactNode {
    if (!icon) return null;
    // "dot" keyword → pulsing severity dot
    if (icon === 'dot') {
        return (
            <span style={{
                display: 'inline-block',
                width: 6, height: 6,
                borderRadius: '50%',
                backgroundColor: color,
                flexShrink: 0,
            }} />
        );
    }
    // React element passed directly
    if (React.isValidElement(icon)) return icon;
    if (typeof icon !== 'string') return null;
    // PrimeReact icon class (e.g. "pi pi-check")
    if (icon.startsWith('pi ')) {
        return <i className={icon} style={{fontSize: iconSize, color: 'inherit'}} />;
    }
    // Lucide icon name from IconMap (e.g. "check-circle-2", "circle-check")
    const Component = IconMap[icon as IconName];
    if (Component) return <Component size={iconSize} />;
    return null;
}

/**
 * Badge component — no PrimeReact dependency.
 *
 * icon prop supports:
 *   - "dot"                → pulsing severity-colored circle
 *   - "check-circle-2"    → lucide icon name from IconMap
 *   - "pi pi-check"       → PrimeReact icon class string
 *   - <MyIcon size={14}/> → React element
 *
 * severity drives colors via kitsTheme severity system.
 * Default style: tinted background (bgTint) + dark text (text) + border.
 * outlined: transparent bg + solid text + solid border.
 */
export function Badge(rawProps: IBadgeProps) {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('Badge', rawProps);
    const {
        value,
        children,
        severity = 'brand',
        size: rawSize,
        outlined,
        icon,
        className,
        testID,
        style,
        ...rest
    } = props;

    const {cssProps, nativeProps} = useSeparator<HTMLSpanElement>(rest);

    // Normalize size — accept string literals safely
    const sizeStr = String(rawSize ?? 'md');
    const size: 'sm' | 'md' | 'lg' =
        sizeStr === 'sm' || sizeStr === 'md' || sizeStr === 'lg' ? sizeStr : 'md';
    const sizeConfig = SIZE_MAP[size];

    const sevColors = useSeverityColors((severity as any) ?? 'secondary');

    /* ── Severity styles ── */
    const severityStyles = useMemo(() => {
        if (outlined) {
            return {
                backgroundColor: 'transparent',
                color: sevColors.solid,
                borderWidth: '1px',
                borderStyle: 'solid' as const,
                borderColor: sevColors.solid,
            };
        }
        return {
            backgroundColor: sevColors.bgTint,
            color: sevColors.text,
            borderWidth: '1px',
            borderStyle: 'solid' as const,
            borderColor: sevColors.border,
        };
    }, [outlined, sevColors]);

    /* ── Resolve icon ── */
    const iconColor = outlined ? sevColors.solid : sevColors.iconFg;
    const resolvedIcon = resolveIcon(icon, sevColors.solid, sizeConfig.iconSize);

    const content = value ?? children;

    const computedCss = {
        ...themeStyle,
        ...(elementStyles.root || {}),
        ...cssProps,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center',
        gap: resolvedIcon ? sizeConfig.gap : 0,
        fontSize: sizeConfig.fontSize,
        fontWeight: '600',
        lineHeight: '1',
        paddingLeft: sizeConfig.px,
        paddingRight: sizeConfig.px,
        paddingTop: sizeConfig.py,
        paddingBottom: sizeConfig.py,
        borderRadius: 6,
        whiteSpace: 'nowrap',
        ...severityStyles,
        ...style,
    };

    return (
        <ResponsiveElement
            as="span"
            //@ts-ignore
            cssProps={computedCss}
            nativeProps={{
                ...nativeProps,
                className,
                "data-testid": testID,
            }}
        >
            {resolvedIcon}
            {content != null && <span style={{lineHeight: 'inherit'}}>{content}</span>}
        </ResponsiveElement>
    );
}

export default Badge;
